(function(){
  // Minimal lightweight Markdown -> HTML converter used as a local fallback for marked
  // Supports headings, paragraphs, code fences, inline code, bold, italic, and links.
  function escapeHtml(s){ return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
  function parse(md){
    if (!md) return '';
    // Handle fenced code blocks ```lang\n...```
    md = md.replace(/```([\s\S]*?)```/g, function(_, code){ return '\n<pre><code>' + escapeHtml(code.trim()) + '</code></pre>\n'; });
    const lines = md.split(/\r?\n/);
    const out = [];
    let buffer = [];
    function flushBuffer(){
      if (!buffer.length) return;
      const text = buffer.join('\n').trim();
      buffer = [];
      if (!text) return;
      // headings
      const h = text.match(/^(#{1,6})\s+(.*)$/m);
      if (h && text.split('\n').length===1){
        const lvl = Math.min(6, h[1].length);
        out.push('<h'+lvl+'>' + inline(h[2]) + '</h'+lvl+'>');
      } else {
        out.push('<p>' + inline(text).replace(/\n/g,'<br>') + '</p>');
      }
    }
    function inline(s){
      if (!s) return '';
      // escape then replace simple patterns
      s = escapeHtml(s);
      // links [text](url)
      s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, function(_, txt, href){ return '<a href="'+href.replace(/"/g,'&quot;')+'">'+txt+'</a>'; });
      // bold **text**
      s = s.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
      // italic *text*
      s = s.replace(/\*([^*]+)\*/g, '<em>$1</em>');
      // inline code `code`
      s = s.replace(/`([^`]+)`/g, function(_, c){ return '<code>'+escapeHtml(c)+'</code>'; });
      return s;
    }
    for (let i=0;i<lines.length;i++){
      const ln = lines[i];
      if (ln.trim() === ''){
        flushBuffer();
        continue;
      }
      // Already handled fenced code as raw HTML string line(s)
      buffer.push(ln);
    }
    flushBuffer();
    return out.join('\n');
  }
  window.marked = window.marked || { parse: parse };
})();
